40	// IssueKind is the machine-readable category for a GraphIssue.
41	type IssueKind string
42	
43	const (
44		IssueDuplicateID         IssueKind = "duplicate_id"
45		IssueParseError          IssueKind = "parse_error"
46		IssueMissingDep          IssueKind = "missing_dep"
47		IssueIDPathMissing       IssueKind = "id_path_missing"
48		IssueIDPathMismatch      IssueKind = "id_path_mismatch"
49		IssueRequiredRootMissing IssueKind = "required_root_missing"
50		IssueCascadeUnknown      IssueKind = "cascade_unknown"
51		IssueCycle               IssueKind = "cycle"
