67	// SuggestUniqueID returns a deterministic unique ID suggestion for a duplicate.
68	// Given the same (id, path) inputs it always returns the same output. The
69	// suggestion appends a short 8-character hex hash of the path so operators can
70	// copy-paste a drop-in replacement without collision anxiety.
71	func SuggestUniqueID(id, path string) string {
72		trimmedID := strings.TrimSpace(id)
73		trimmedPath := strings.TrimSpace(path)
74		sum := sha1.Sum([]byte(trimmedPath))
75		suffix := hex.EncodeToString(sum[:])[:8]
76		if trimmedID == "" {
77			return "doc-" + suffix
78		}
79		return trimmedID + "-" + suffix
80	}
