124	// MessageLines returns the human-readable message strings for a set of issues,
125	// sorted for stable output. Callers that historically consumed
126	// Graph.Warnings can use issues.MessageLines() once migrated.
127	func MessageLines(issues []GraphIssue) []string {
128		if len(issues) == 0 {
129			return nil
130		}
131		out := make([]string, 0, len(issues))
132		for _, issue := range issues {
133			out = append(out, issue.Message)
134		}
135		sort.Strings(out)
136		return out
137	}
