151	func BuildGraphWithConfig(workingDir string) (*Graph, error) {
152		configs, err := LoadGraphConfigs(workingDir)
153		if err != nil {
154			return nil, err
155		}
156		if len(configs) == 0 {
157			return BuildGraph(workingDir)
158		}
159	
160		roots := make([]string, 0, len(configs))
161		for _, cfg := range configs {
162			for _, root := range cfg.Roots {
163				if root == "" {
164					continue
165				}
166				roots = append(roots, filepath.Join(workingDir, root))
167			}
168		}
169		if len(roots) == 0 {
170			return BuildGraph(workingDir)
171		}
172	
173		graph, err := buildGraph(workingDir, roots)
174		if err != nil {
175			return nil, err
176		}
177		graph.applyConfig(configs)
