181	func buildGraph(workingDir string, roots []string) (*Graph, error) {
182		files, err := findMarkdownFiles(workingDir, roots)
183		if err != nil {
184			return nil, err
185		}
186	
187		cleanRoot := filepath.Clean(workingDir)
188		documents := make(map[string]*Document)
189		pathToID := make(map[string]string)
190		issues := []GraphIssue{}
191		for _, filePath := range files {
192			doc, err := ParseDocument(filePath)
193			if err != nil {
194				if errors.Is(err, ErrNotDocGraphDocument) {
195					continue
196				}
197				if errors.Is(err, ErrPromptMetadataOversize) {
198					return nil, err
199				}
200				issues = append(issues, GraphIssue{
201					Kind:    IssueParseError,
202					Path:    relPath(cleanRoot, filePath),
203					Message: fmt.Sprintf("%s: %v", filePath, err),
204				})
205				continue
206			}
207			if existing, exists := documents[doc.ID]; exists {
208				issues = append(issues, GraphIssue{
209					Kind:        IssueDuplicateID,
210					Path:        relPath(cleanRoot, filePath),
211					ID:          doc.ID,
212					Message:     fmt.Sprintf("duplicate document id %q in %q", doc.ID, filePath),
213					RelatedPath: existing.Path,
214				})
215				continue
216			}
217			doc.Path = relPath(cleanRoot, filePath)
218			documents[doc.ID] = doc
219			pathToID[doc.Path] = doc.ID
220		}
221	
222		g := &Graph{
223			RootDir:   cleanRoot,
224			Documents: documents,
225			PathToID:  pathToID,
226			Issues:    issues,
227		}
228		g.resolveBodyLinks()
229		g.buildDependents()
230		g.detectMissingDeps()
231		g.detectCycles()
232		g.applyConfigDefaults()
233		g.finalizeWarnings()
234		return g, nil
235	}
