237	// detectMissingDeps emits missing_dep issues for every declared dependency
238	// that does not resolve to a document in the graph. Runs after body-link
239	// resolution so link targets are already promoted to DependsOn.
240	func (g *Graph) detectMissingDeps() {
241		for _, id := range sortedDocIDs(g.Documents) {
242			doc := g.Documents[id]
243			if doc == nil {
244				continue
245			}
246			for _, dep := range doc.DependsOn {
247				if _, ok := g.Documents[dep]; ok {
248					continue
249				}
250				g.Issues = append(g.Issues, GraphIssue{
251					Kind:    IssueMissingDep,
252					Path:    doc.Path,
253					ID:      dep,
254					Message: fmt.Sprintf("document %q declares dependency %q which is not in the graph", doc.ID, dep),
255				})
256			}
257		}
258	}
