260	// sortedDocIDs returns the IDs of docs sorted for stable issue ordering.
261	func sortedDocIDs(docs map[string]*Document) []string {
262		ids := make([]string, 0, len(docs))
263		for id := range docs {
264			ids = append(ids, id)
265		}
266		sort.Strings(ids)
267		return ids
