270	// finalizeWarnings rebuilds the deprecated Warnings string slice from Issues
271	// and sorts Issues deterministically so downstream callers see stable output.
272	func (g *Graph) finalizeWarnings() {
273		sort.SliceStable(g.Issues, func(i, j int) bool {
274			if g.Issues[i].Kind != g.Issues[j].Kind {
275				return g.Issues[i].Kind < g.Issues[j].Kind
276			}
277			return g.Issues[i].Message < g.Issues[j].Message
278		})
279		g.Warnings = MessageLines(g.Issues)
280		if g.Warnings == nil {
281			g.Warnings = []string{}
282		}
283	}
