292	func (g *Graph) applyConfig(configs []GraphConfig) {
293		if len(configs) == 0 {
294			return
295		}
296	
297		idToPath := make(map[string]string)
298		cascade := make(map[string][]string)
299		for _, cfg := range configs {
300			for id, rawPath := range cfg.IDToPath {
301				if id == "" || rawPath == "" {
302					continue
303				}
304				idToPath[id] = filepath.Clean(filepath.Join(g.RootDir, rawPath))
305			}
306			for from, tos := range cfg.Cascade {
307				for _, to := range tos {
308					if from == "" || to == "" {
309						continue
310					}
311					cascade[from] = append(cascade[from], to)
312				}
313			}
314			if len(cfg.IDMap) > 0 {
315				for id, rawPath := range cfg.IDMap {
316					if id == "" || rawPath == "" {
317						continue
318					}
319					idToPath[id] = filepath.Clean(filepath.Join(g.RootDir, rawPath))
320				}
321			}
322			if len(cfg.Required) > 0 {
323				for _, id := range cfg.Required {
324					if _, ok := g.Documents[id]; !ok {
325						g.Issues = append(g.Issues, GraphIssue{
326							Kind:    IssueRequiredRootMissing,
327							ID:      id,
328							Message: fmt.Sprintf("required root document %q not found", id),
329						})
330					}
331				}
332			}
333		}
334	
335		if len(idToPath) > 0 {
336			for id, path := range idToPath {
337				if _, ok := g.Documents[id]; ok {
338					continue
339				}
340				if _, err := os.Stat(path); err != nil {
341					g.Issues = append(g.Issues, GraphIssue{
342						Kind:    IssueIDPathMissing,
343						ID:      id,
344						Path:    relPath(g.RootDir, path),
345						Message: fmt.Sprintf("id_to_path entry %q -> %q does not exist", id, path),
346					})
347					continue
348				}
349				doc, err := ParseDocument(path)
350				if err != nil {
351					if errors.Is(err, ErrNotDocGraphDocument) {
352						g.Issues = append(g.Issues, GraphIssue{
353							Kind:    IssueIDPathMissing,
354							ID:      id,
355							Path:    relPath(g.RootDir, path),
356							Message: fmt.Sprintf("id_to_path entry %q -> %q is not a doc graph document", id, path),
357						})
358						continue
359					}
360					g.Issues = append(g.Issues, GraphIssue{
361						Kind:    IssueIDPathMissing,
362						ID:      id,
363						Path:    relPath(g.RootDir, path),
364						Message: fmt.Sprintf("id_to_path entry %q -> %q could not be loaded: %v", id, path, err),
365					})
366					continue
367				}
368				if doc.ID != id {
369					g.Issues = append(g.Issues, GraphIssue{
370						Kind:    IssueIDPathMismatch,
371						ID:      id,
372						Path:    relPath(g.RootDir, path),
373						Message: fmt.Sprintf("id_to_path mismatch for %q: %q declares %q", id, path, doc.ID),
374					})
375					continue
376				}
377				g.Documents[id] = doc
378				doc.Path = relPath(g.RootDir, path)
379				g.PathToID[doc.Path] = id
380			}
381		}
382	
383		for from, toIDs := range cascade {
384			if _, ok := g.Documents[from]; !ok {
385				g.Issues = append(g.Issues, GraphIssue{
386					Kind:    IssueCascadeUnknown,
387					ID:      from,
388					Message: fmt.Sprintf("cascade rule refers to unknown dependency root %q", from),
389				})
390				continue
391			}
392			for _, to := range dedupeSortedStrings(toIDs) {
393				if to == "" {
394					continue
395				}
396				child, ok := g.Documents[to]
397				if !ok {
398					g.Issues = append(g.Issues, GraphIssue{
399						Kind:    IssueCascadeUnknown,
400						ID:      to,
401						Message: fmt.Sprintf("cascade rule refers to unknown target doc %q", to),
402					})
403					continue
404				}
405				if !containsString(child.DependsOn, from) {
406					child.DependsOn = append(child.DependsOn, from)
407				}
408			}
409		}
410	
411		for id := range g.Documents {
412			g.Documents[id].DependsOn = dedupeSortedStrings(g.Documents[id].DependsOn)
413		}
414		g.buildDependents()
415		// Re-run integrity scans that can change after id_to_path/cascade apply.
416		g.rescanAfterConfig()
417		g.detectCycles()
418		g.finalizeWarnings()
419	}
