421	// rescanAfterConfig refreshes integrity detections that depend on the final
422	// document set. Currently this just re-runs missing-dep detection so deps
423	// pulled in by cascade rules or id_to_path entries are evaluated, and dedupes
424	// any duplicate issues introduced by the rescan.
425	func (g *Graph) rescanAfterConfig() {
426		// Wipe prior missing_dep entries because applyConfig may have resolved
427		// some of them by promoting id_to_path targets into Documents.
428		filtered := g.Issues[:0]
429		for _, issue := range g.Issues {
430			if issue.Kind == IssueMissingDep {
431				continue
432			}
433			filtered = append(filtered, issue)
434		}
435		g.Issues = filtered
436		g.detectMissingDeps()
437	}
