439	func findMarkdownFiles(root string, roots []string) ([]string, error) {
440		targetDirs := []string{root}
441		if len(roots) > 0 {
442			targetDirs = roots
443		}
444	
445		files := []string{}
446		for _, base := range targetDirs {
447			cleanRoot := filepath.Clean(base)
448			err := filepath.Walk(cleanRoot, func(path string, info os.FileInfo, err error) error {
449				if err != nil {
450					return nil
451				}
452				if info == nil {
453					return nil
454				}
455				if info.IsDir() {
456					name := filepath.Base(path)
457					// Skip tool-managed directories. .claude and .agents are
458					// agent-skill workspaces that often contain stale copies of
459					// canonical docs; a worktrees/ directory at any depth is
460					// agent-scratch and must not be surfaced as canonical documents.
461					switch name {
462					case ".git", ".ddx", ".claude", ".agents", "worktrees":
463						return filepath.SkipDir
464					}
465					return nil
466				}
467				if strings.HasPrefix(filepath.Base(path), ".") {
468					return nil
469				}
470				ext := strings.ToLower(filepath.Ext(path))
471				if ext != ".md" {
472					return nil
473				}
474				files = append(files, path)
475				return nil
476			})
477			if err != nil {
478				return nil, err
479			}
480		}
481		sort.Strings(files)
482		return files, nil
483	}
