564	// HashDocumentFile parses the markdown file at path and returns the
565	// deterministic document content hash, or an error if the file is not a doc
566	// graph document. The hash matches Document.ContentHash() for the same file.
567	func HashDocumentFile(path string) (string, error) {
568		doc, err := ParseDocument(path)
569		if err != nil {
570			return "", err
