575	func (g *Graph) buildDependents() {
576		g.Dependents = make(map[string][]string)
577		for id := range g.Documents {
578			g.Dependents[id] = g.Dependents[id][:0]
579		}
580		for id, doc := range g.Documents {
581			for _, dep := range doc.DependsOn {
582				if _, ok := g.Documents[dep]; !ok {
583					continue
584				}
585				if containsString(g.Dependents[dep], id) {
586					continue
587				}
588				g.Dependents[dep] = append(g.Dependents[dep], id)
589			}
590		}
591		for id := range g.Dependents {
592			g.Dependents[id] = dedupeSortedStrings(g.Dependents[id])
593		}
594		for id, doc := range g.Documents {
595			doc.Dependents = append([]string{}, g.Dependents[id]...)
596		}
597	}
