599	func (g *Graph) detectCycles() {
600		index := 0
601		indexes := map[string]int{}
602		lowlinks := map[string]int{}
603		onStack := map[string]bool{}
604		stack := []string{}
605		warned := map[string]struct{}{}
606		var visit func(string)
607	
608		visit = func(id string) {
609			indexes[id] = index
610			lowlinks[id] = index
611			index++
612			stack = append(stack, id)
613			onStack[id] = true
614	
615			node := g.Documents[id]
616			for _, dep := range node.DependsOn {
617				if _, ok := g.Documents[dep]; !ok {
618					continue
619				}
620				if _, ok := indexes[dep]; !ok {
621					visit(dep)
622					if lowlinks[dep] < lowlinks[id] {
623						lowlinks[id] = lowlinks[dep]
624					}
625				} else if onStack[dep] {
626					if indexes[dep] < lowlinks[id] {
627						lowlinks[id] = indexes[dep]
628					}
629				}
630			}
631	
632			if lowlinks[id] == indexes[id] {
633				cycle := []string{}
634				for {
635					last := stack[len(stack)-1]
636					stack = stack[:len(stack)-1]
637					onStack[last] = false
638					cycle = append(cycle, last)
639					if last == id {
640						break
641					}
642				}
643				if len(cycle) > 1 {
644					warnKey := cycleKey(cycle)
645					if _, done := warned[warnKey]; done {
646						return
647					}
648					warned[warnKey] = struct{}{}
649					label := renderCycle(cycle)
650					g.Issues = append(g.Issues, GraphIssue{
651						Kind:    IssueCycle,
652						Message: fmt.Sprintf("cycle detected: %s", label),
653					})
654				} else {
655					parent := g.Documents[id]
656					selfDepends := containsString(parent.DependsOn, id)
657					if selfDepends {
658						label := fmt.Sprintf("%s -> %s", id, id)
659						g.Issues = append(g.Issues, GraphIssue{
660							Kind:    IssueCycle,
661							ID:      id,
662							Message: fmt.Sprintf("cycle detected: %s", label),
663						})
664					}
665				}
666			}
667		}
