1011	// for ID matching. Dots are preserved (dotted IDs). Spaces and underscores
1012	// become hyphens. Other non-alphanumeric characters are dropped.
1013	func slugifyID(text string) string {
1014		var b strings.Builder
1015		prevHyphen := false
1016		for _, r := range strings.ToLower(text) {
1017			switch {
1018			case unicode.IsLetter(r) || unicode.IsDigit(r) || r == '.':
1019				b.WriteRune(r)
