1021			case r == '-' || r == '_' || unicode.IsSpace(r):
1022				if !prevHyphen && b.Len() > 0 {
1023					b.WriteByte('-')
1024					prevHyphen = true
1025				}
1026			}
1027		}
1028		result := b.String()
